func rotate(nums []int, k int) {
	idx := 0
	temp := make([]int, len(nums))
	for i := 0; i < len(nums); i++ {
		idx = (i + k) % len(nums)
		temp[idx] = nums[i]
	}
	// for i,v := range temp {
	//     nums[i] = v
	// }
	for i := 0; i < len(nums); i++ {
		nums[i] = temp[i]
	}
}

